<# ─────────────────────────────────────────────────────────────────────────────
   通信原理仿真软件 — 自安装启动器
   无需预装 Python，首次运行自动配置，后续秒启。
   ─────────────────────────────────────────────────────────────────────────────#>
param([switch]$Uninstall)
$ErrorActionPreference = "Stop"
$ProgressPreference    = "SilentlyContinue"

# ── 配置 ──────────────────────────────────────────────────────────────────────
$AppName    = "通信原理仿真软件"
$AppDir     = Join-Path $env:LOCALAPPDATA "CommSimLab"
$PyDir      = Join-Path $AppDir "python"
$SrcDir     = Join-Path $AppDir "src_app"
$PkgDir     = Join-Path $AppDir "packages"
$PyExe      = Join-Path $PyDir  "python.exe"
$PyUrl      = "https://www.python.org/ftp/python/3.11.9/python-3.11.9-embed-amd64.zip"
$PipUrl     = "https://bootstrap.pypa.io/get-pip.py"
$LogFile    = Join-Path $AppDir "setup.log"
$DoneMarker = Join-Path $AppDir ".setup_done"

function Write-Step($msg) {
    Write-Host "  $msg" -ForegroundColor Cyan
    Add-Content $LogFile "$(Get-Date -f 'HH:mm:ss')  $msg"
}
function Write-OK($msg)   { Write-Host "  ✓ $msg" -ForegroundColor Green }
function Write-Err($msg)  { Write-Host "  ✗ $msg" -ForegroundColor Red; throw $msg }

# ── 卸载模式 ──────────────────────────────────────────────────────────────────
if ($Uninstall) {
    if (Test-Path $AppDir) { Remove-Item $AppDir -Recurse -Force }
    Write-Host "$AppName 已卸载。" -ForegroundColor Yellow
    exit 0
}

# ── 欢迎横幅 ──────────────────────────────────────────────────────────────────
Clear-Host
Write-Host ""
Write-Host "  ╔══════════════════════════════════════════════╗" -ForegroundColor Blue
Write-Host "  ║      通信原理仿真软件  v1.0                  ║" -ForegroundColor Blue
Write-Host "  ║   Communications Simulation Lab              ║" -ForegroundColor Blue
Write-Host "  ╚══════════════════════════════════════════════╝" -ForegroundColor Blue
Write-Host ""

New-Item $AppDir -ItemType Directory -Force | Out-Null
Set-Content $LogFile "=== Setup log $(Get-Date) ==="

# ── 检查是否已安装 ─────────────────────────────────────────────────────────────
if (-not (Test-Path $DoneMarker)) {
    Write-Host "  首次运行，正在配置环境..." -ForegroundColor Yellow
    Write-Host ""

    # 1. 下载 Python Embeddable
    Write-Step "下载 Python 3.11 Embeddable (≈26MB)..."
    $PyZip = Join-Path $AppDir "python_embed.zip"
    if (-not (Test-Path $PyZip)) {
        try {
            Invoke-WebRequest $PyUrl -OutFile $PyZip -UseBasicParsing
            Write-OK "Python 下载完成"
        } catch {
            Write-Err "Python 下载失败，请检查网络连接: $_"
        }
    } else {
        Write-OK "Python 已缓存，跳过下载"
    }

    # 2. 解压 Python
    Write-Step "解压 Python..."
    New-Item $PyDir -ItemType Directory -Force | Out-Null
    Expand-Archive $PyZip $PyDir -Force
    Write-OK "Python 解压完成"

    # 3. 启用 site-packages（修改 ._pth 文件）
    $pth = Get-ChildItem $PyDir -Filter "python*._pth" | Select-Object -First 1
    if ($pth) {
        $content = Get-Content $pth.FullName -Raw
        $content = $content -replace "#import site", "import site"
        $content += "`n$PkgDir`n"
        Set-Content $pth.FullName $content
        Write-OK "site-packages 已启用"
    }

    # 4. 下载并安装 pip
    Write-Step "安装 pip..."
    $GetPip = Join-Path $AppDir "get-pip.py"
    Invoke-WebRequest $PipUrl -OutFile $GetPip -UseBasicParsing
    New-Item $PkgDir -ItemType Directory -Force | Out-Null
    & $PyExe $GetPip --target $PkgDir --quiet 2>&1 | Out-Null
    Write-OK "pip 安装完成"

    # 5. 安装依赖包
    $packages = @("PyQt5", "numpy", "scipy", "matplotlib")
    foreach ($pkg in $packages) {
        Write-Step "安装 $pkg ..."
        & $PyExe -m pip install $pkg --target $PkgDir --quiet 2>&1 | Out-Null
        Write-OK "$pkg 完成"
    }

    # 6. 解压源码
    Write-Step "部署程序文件..."
    New-Item $SrcDir -ItemType Directory -Force | Out-Null
    $SrcZip = Join-Path $AppDir "src_app.zip"

    # 内嵌的 base64 源码包
    $b64 = @'

'@
    $bytes = [Convert]::FromBase64String($b64.Trim())
    [IO.File]::WriteAllBytes($SrcZip, $bytes)
    Expand-Archive $SrcZip $SrcDir -Force
    Write-OK "程序文件部署完成"

    # 7. 创建桌面快捷方式
    Write-Step "创建桌面快捷方式..."
    $LauncherPs = Join-Path $AppDir "launch.ps1"
    @"
`$ErrorActionPreference = 'Continue'
`$AppDir  = '$AppDir'
`$PyExe   = '$PyExe'
`$PkgDir  = '$PkgDir'
`$SrcDir  = '$SrcDir'
`$env:PYTHONPATH = `$PkgDir
Set-Location `$SrcDir
& `$PyExe main.py
"@ | Set-Content $LauncherPs

    $ShellObj = New-Object -ComObject WScript.Shell
    $Desktop  = [Environment]::GetFolderPath("Desktop")
    $Shortcut = $ShellObj.CreateShortcut("$Desktop\通信原理仿真软件.lnk")
    $Shortcut.TargetPath       = "powershell.exe"
    $Shortcut.Arguments        = "-WindowStyle Hidden -ExecutionPolicy Bypass -File `"$LauncherPs`""
    $Shortcut.WorkingDirectory = $SrcDir
    $Shortcut.Description      = "通信原理仿真软件"
    $Shortcut.Save()
    Write-OK "桌面快捷方式已创建"

    Set-Content $DoneMarker (Get-Date).ToString()
    Write-Host ""
    Write-Host "  ══════════ 安装完成！══════════" -ForegroundColor Green
    Write-Host ""
}

# ── 启动程序 ──────────────────────────────────────────────────────────────────
Write-Host "  正在启动 $AppName ..." -ForegroundColor Cyan
$env:PYTHONPATH = $PkgDir
Set-Location $SrcDir
& $PyExe (Join-Path $SrcDir "main.py")
